// 鉄の掟準拠：環境変数必須チェック
const apiUrl = $env.N3_API_URL || $env.API_BASE_URL;

if (!apiUrl) {
  return [{ json: { error: true, message: 'N3_API_URL環境変数が未設定', code: 'CONFIG_ERROR' } }];
}

const body = $input.first().json.body || $input.first().json || {};
const extractionId = body.extraction_id;
const targetPlatforms = body.target_platforms || ['ebay', 'shopify'];

if (!extractionId) {
  return [{ json: { error: true, message: 'extraction_id は必須', code: 'MISSING_PARAM' } }];
}

return [{
  json: {
    extraction_id: extractionId,
    target_platforms: targetPlatforms,
    api_url: apiUrl,
    timestamp: new Date().toISOString()
  }
}];

const initData = $node['🔐 初期化（鉄の掟準拠）'].json;
const extractionData = $input.first().json;

if (!extractionData || !extractionData.extraction_id) {
  return [{ json: { error: true, message: '抽出データが見つかりません', code: 'NOT_FOUND' } }];
}

const products = typeof extractionData.products_data === 'string'
  ? JSON.parse(extractionData.products_data)
  : extractionData.products_data || [];

return products.map((product, index) => ({
  json: {
    ...initData,
    extraction_id: extractionData.extraction_id,
    video_url: extractionData.video_url,
    product_index: index,
    product: product
  }
}));

// eBay出品データ生成
const data = $input.first().json;
const product = data.product;

const ebayListing = {
  title: (product.product_name?.en || product.product_name || '').substring(0, 80),
  description: `<html><body>
    <h1>${product.product_name?.en || product.product_name}</h1>
    <p>${product.description || ''}</p>
    <h2>Features</h2>
    <ul>${(product.features || []).map(f => `<li>${f}</li>`).join('')}</ul>
    <h2>Specifications</h2>
    <ul>${Object.entries(product.specifications || {}).map(([k, v]) => `<li><strong>${k}:</strong> ${v}</li>`).join('')}</ul>
    <p><em>Extracted from video review</em></p>
  </body></html>`,
  category_id: product.category?.ebay_id || '0',
  price: product.estimated_price_range?.max || 99.99,
  quantity: 1,
  condition_id: 1000, // New
  item_specifics: product.specifications || {},
  keywords: product.keywords || []
};

// Shopify商品データ生成
const shopifyProduct = {
  title: product.product_name?.en || product.product_name || '',
  body_html: `<p>${product.description || ''}</p>
    <h3>Features</h3>
    <ul>${(product.features || []).map(f => `<li>${f}</li>`).join('')}</ul>`,
  vendor: 'Video Commerce',
  product_type: product.category?.name || 'General',
  tags: (product.keywords || []).join(', '),
  variants: [{
    price: product.estimated_price_range?.max || '99.99',
    sku: `VC-${data.extraction_id}-${data.product_index}`,
    inventory_quantity: 1
  }]
};

return [{
  json: {
    ...data,
    ebay_listing: ebayListing,
    shopify_product: shopifyProduct
  }
}];

const allItems = $input.all();
const results = allItems.map(item => item.json).filter(r => r && r.listing_id);

return [{
  json: {
    success: true,
    action: 'listings_generated',
    generated_count: results.length,
    listing_ids: results.map(r => r.listing_id),
    timestamp: new Date().toISOString()
  }
}];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
